import{_ as e,C as p,o as l,c as t,ag as n,E as i}from"./chunks/framework.CAXxHpAX.js";const g=JSON.parse('{"title":"10. 向量数据库：面向 AI / RAG / 语义检索的数据系统","description":"把非结构化数据转成可检索语义空间，理解 RAG、混合检索和向量治理。","frontmatter":{"title":"10. 向量数据库：面向 AI / RAG / 语义检索的数据系统","description":"把非结构化数据转成可检索语义空间，理解 RAG、混合检索和向量治理。","prev":{"text":"9. OLAP 数据库：ClickHouse / Doris / DuckDB","link":"/chapters/09-olap-databases"},"next":{"text":"11. 图数据库：面向关系网络 / 知识图谱 / 路径分析的数据系统","link":"/chapters/11-graph-databases"}},"headers":[],"relativePath":"chapters/10-vector-databases.md","filePath":"chapters/10-vector-databases.md"}'),r={name:"chapters/10-vector-databases.md"};function d(c,a,o,b,u,h){const s=p("Mermaid");return l(),t("div",null,[a[0]||(a[0]=n('<h1 id="_10-向量数据库-面向-ai-rag-语义检索的数据系统" tabindex="-1">10. 向量数据库：面向 AI / RAG / 语义检索的数据系统 <a class="header-anchor" href="#_10-向量数据库-面向-ai-rag-语义检索的数据系统" aria-label="Permalink to &quot;10. 向量数据库：面向 AI / RAG / 语义检索的数据系统&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">本章导读</p><p>把非结构化数据转成可检索语义空间，理解 RAG、混合检索和向量治理。</p></div><h2 id="本章阅读框架" tabindex="-1">本章阅读框架 <a class="header-anchor" href="#本章阅读框架" aria-label="Permalink to &quot;本章阅读框架&quot;">​</a></h2><table tabindex="0"><thead><tr><th>阅读问题</th><th>本章回答方式</th></tr></thead><tbody><tr><td>这个问题为什么出现？</td><td>从业务增长、数据规模、系统目标或 AI 应用压力切入。</td></tr><tr><td>它解决什么问题？</td><td>提炼为一个核心判断，避免把概念写成孤立定义。</td></tr><tr><td>它不解决什么问题？</td><td>在机制解释和常见误区中说明边界，防止工具崇拜。</td></tr><tr><td>它在真实平台哪里出现？</td><td>放回 PostgreSQL、数仓、批流、OLAP、湖仓、向量、图和治理的演化链路。</td></tr><tr><td>读完要会做什么？</td><td>通过场景案例和实战任务转成可练习的判断。</td></tr></tbody></table>',4)),i(s,{code:"flowchart%20LR%0A%20%20D%5B%22%E6%96%87%E6%A1%A3%22%5D%20--%3E%20P%5B%22%E8%A7%A3%E6%9E%90%22%5D%0A%20%20P%20--%3E%20C%5B%22Chunking%22%5D%0A%20%20C%20--%3E%20E%5B%22Embedding%22%5D%0A%20%20E%20--%3E%20V%5B%22Vector%20DB%22%5D%0A%20%20Q%5B%22Query%22%5D%20--%3E%20QE%5B%22Query%20Embedding%22%5D%0A%20%20QE%20--%3E%20V%0A%20%20V%20--%3E%20R%5B%22Rerank%22%5D%0A%20%20R%20--%3E%20L%5B%22LLM%20Context%22%5D%0A"}),a[1]||(a[1]=n(`<p>传统数据库擅长回答结构化问题。</p><h2 id="问题切入" tabindex="-1">问题切入 <a class="header-anchor" href="#问题切入" aria-label="Permalink to &quot;问题切入&quot;">​</a></h2><p>例如：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>订单金额大于 100 的记录</span></span>
<span class="line"><span>某个用户最近 20 笔订单</span></span>
<span class="line"><span>某天 GMV 总和</span></span>
<span class="line"><span>某类商品销量排行</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>但 AI 应用经常要回答另一类问题：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>哪些文档和这个问题语义相似？</span></span>
<span class="line"><span>哪些图片和这张图片相似？</span></span>
<span class="line"><span>哪些代码片段和这个需求相关？</span></span>
<span class="line"><span>哪些历史对话可以作为 Agent 记忆？</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>这些问题不是简单等值匹配，而是语义相似性检索。</p><p>第 9 章的 OLAP 数据库解决的是结构化分析查询：过滤、聚合、排序、分组和多维下钻。但 AI 应用经常面对的是文档、图片、代码、对话、网页、知识片段和操作记录。这些数据不一定能先被整理成整齐的行列，也不一定能通过关键词精确匹配找到。</p><p>一个企业知识库的真实问题通常不是：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>WHERE title = &#39;报销制度&#39;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>而是：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>“出差打车超过预算还能报销吗？”</span></span>
<span class="line"><span>“客户合同里的自动续约条款在哪里？”</span></span>
<span class="line"><span>“这个报错和过去哪个工单最像？”</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>这些问题需要先把非结构化内容变成可检索的语义表示，再把检索结果和权限、来源、版本、上下文、评测结合起来。</p><h2 id="核心判断" tabindex="-1">核心判断 <a class="header-anchor" href="#核心判断" aria-label="Permalink to &quot;核心判断&quot;">​</a></h2><blockquote><p>向量数据库不是传统数据库替代品，它解决的是非结构化数据进入 AI 应用后的语义检索问题。</p></blockquote><p>本章要建立的判断是：向量数据库让“语义相似”成为一种可查询能力，但它只解决 RAG 和 AI 数据系统中的召回问题，不解决全部可信问题。</p><p>一个可用的 AI 数据系统不仅需要向量检索，还需要文档解析、分块、Embedding 版本、元数据、权限过滤、重排、上下文组装、检索日志、评测和治理。把向量数据库当成 AI 数据基础设施的全部，是最常见的误判。</p><h2 id="机制解释" tabindex="-1">机制解释 <a class="header-anchor" href="#机制解释" aria-label="Permalink to &quot;机制解释&quot;">​</a></h2><h3 id="_10-1-基础概念" tabindex="-1">10.1 基础概念 <a class="header-anchor" href="#_10-1-基础概念" aria-label="Permalink to &quot;10.1 基础概念&quot;">​</a></h3><p>Embedding 是把文本、图片、音频、代码等对象转换成向量的过程。</p><p>Vector 是一组数字，表示对象在语义空间中的位置。</p><p>Dimension 是向量维度。</p><p>Similarity Search 是相似性搜索。</p><p>Approximate Nearest Neighbor 是近似最近邻搜索，用一定精度换取更快检索。</p><p>Top-K 是返回最相似的 K 个结果。</p><p>Recall 表示相关结果被召回的比例。</p><p>Precision 表示召回结果中真正相关的比例。</p><p>Metadata Filter 是元数据过滤，例如只检索某个知识库、某个用户权限范围、某个文档类型。</p><p>Hybrid Search 是混合检索，把关键词、全文、向量和元数据过滤结合起来。</p><h3 id="_10-2-向量生成" tabindex="-1">10.2 向量生成 <a class="header-anchor" href="#_10-2-向量生成" aria-label="Permalink to &quot;10.2 向量生成&quot;">​</a></h3><p>向量数据库的第一步不是建库，而是生成向量。</p><p>典型 RAG 数据链路是：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>文档采集</span></span>
<span class="line"><span>  -&gt; 文档解析</span></span>
<span class="line"><span>  -&gt; Chunking</span></span>
<span class="line"><span>  -&gt; Embedding</span></span>
<span class="line"><span>  -&gt; 向量入库</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>Chunking 很关键。</p><p>如果 Chunk 太大，召回内容不精确；如果 Chunk 太小，语义不完整。Chunk 还需要保存来源、位置、标题、权限、版本和解析方式。</p><p>Embedding Model 决定向量空间。模型一旦变化，旧向量和新向量通常不能直接混用。</p><p>因此需要向量版本管理：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>embedding_model</span></span>
<span class="line"><span>embedding_version</span></span>
<span class="line"><span>chunk_version</span></span>
<span class="line"><span>index_version</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>核心判断是：</p><blockquote><p>向量质量不是只由数据库决定，而是由文档解析、切分、模型、版本和索引共同决定。</p></blockquote><h3 id="_10-3-相似度计算" tabindex="-1">10.3 相似度计算 <a class="header-anchor" href="#_10-3-相似度计算" aria-label="Permalink to &quot;10.3 相似度计算&quot;">​</a></h3><p>常见相似度包括：</p><ul><li>Cosine Similarity。</li><li>Dot Product。</li><li>Euclidean Distance。</li><li>Inner Product。</li></ul><p>距离函数不是随便选的，它要和 Embedding 模型训练方式、向量是否归一化、数据库索引类型匹配。</p><p>相似度分数也不是业务答案。</p><p>向量检索只能告诉你“这些内容在向量空间里相近”，不保证事实正确、权限可见、上下文完整或答案可直接生成。</p><p>这就是为什么 RAG 系统还需要元数据过滤、重排、上下文组装和评测。</p><h3 id="_10-4-向量索引" tabindex="-1">10.4 向量索引 <a class="header-anchor" href="#_10-4-向量索引" aria-label="Permalink to &quot;10.4 向量索引&quot;">​</a></h3><p>小规模数据可以 Flat Index 全量比对。</p><p>大规模向量需要索引。</p><p>常见索引包括：</p><ul><li>HNSW。</li><li>IVF。</li><li>IVF_FLAT。</li><li>IVF_PQ。</li><li>DiskANN。</li><li>Quantization。</li></ul><p>这些名称不是同一层级，也不是每个向量数据库都支持。更准确的理解方式是：</p><table tabindex="0"><thead><tr><th>索引或技术</th><th>机制直觉</th><th>典型取舍</th></tr></thead><tbody><tr><td>Flat / 精确搜索</td><td>不建立近似索引，直接比较候选向量</td><td>召回最完整，但数据量和延迟压力最大</td></tr><tr><td>HNSW</td><td>用多层图结构把相近向量连接起来</td><td>查询速度和召回通常较好，但构建更慢、内存占用更高</td></tr><tr><td>IVF / IVF_FLAT</td><td>先把向量划分到多个列表或簇，查询时只搜索部分列表</td><td>构建和内存成本相对可控，但 lists / probes 参数会影响召回和延迟</td></tr><tr><td>IVF_PQ / Quantization</td><td>用量化或压缩表示降低内存和计算成本</td><td>更省资源、更快，但可能引入近似误差和召回下降</td></tr><tr><td>DiskANN / 磁盘型索引</td><td>把更多索引或向量数据放到磁盘路径上</td><td>适合更大规模和内存受限场景，但延迟、硬件和实现参数更敏感</td></tr></tbody></table><p>例如 pgvector 官方支持 HNSW 和 IVFFlat 两类近似索引；Qdrant 的 dense vector index 目前以 HNSW 为核心，同时区分 vector index 和 payload index，并提供 quantization 来降低内存和加速搜索；Milvus 支持 FLAT、IVF_FLAT、IVF_PQ、HNSW、SCANN 以及量化相关索引。真实选型必须回到具体产品、版本、向量类型、距离度量和查询参数，而不是只背索引名称。</p><p>索引带来典型取舍：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>召回率</span></span>
<span class="line"><span>  &lt;-&gt; 查询延迟</span></span>
<span class="line"><span>  &lt;-&gt; 内存成本</span></span>
<span class="line"><span>  &lt;-&gt; 构建时间</span></span>
<span class="line"><span>  &lt;-&gt; 更新成本</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>向量索引的核心判断是：</p><blockquote><p>向量索引用精确度、资源和维护成本，换取大规模相似性检索的速度。</p></blockquote><h3 id="_10-5-向量数据库产品定位" tabindex="-1">10.5 向量数据库产品定位 <a class="header-anchor" href="#_10-5-向量数据库产品定位" aria-label="Permalink to &quot;10.5 向量数据库产品定位&quot;">​</a></h3><p>常见系统包括：</p><ul><li>Milvus / Zilliz Cloud。</li><li>Qdrant。</li><li>Weaviate。</li><li>Pinecone。</li><li>Chroma。</li><li>FAISS。</li><li>pgvector。</li><li>Elasticsearch Vector Search。</li><li>OpenSearch Vector。</li></ul><p>它们不是同一类使用边界。</p><p>FAISS 更像向量检索库，适合嵌入到应用或离线流程中。</p><p>Chroma 适合轻量本地和原型。</p><p>pgvector 适合中小规模 RAG、元数据和权限与向量共存的场景。</p><p>Milvus、Qdrant、Weaviate、Pinecone 更偏专门向量数据库或服务，适合更大规模、更专门的向量检索需求。它们通常把向量集合、向量索引、相似性搜索、标量字段过滤、混合检索、多阶段检索、备份、监控、部署和扩展能力作为产品核心，而不是只提供一个“向量字段”。</p><p>但这里要避免一个误解：过滤能力不等于端到端权限系统。向量数据库可以根据 payload、metadata 或标量字段缩小搜索范围，也可以把稠密向量、稀疏向量、关键词检索或重排组合起来提升召回质量；但“这个用户是否可以看到这段内容”仍然需要由业务权限、数据治理、元数据、服务层鉴权和审计共同保证。专门向量数据库优化的是检索系统，不会自动替代文档解析、Chunk 设计、Embedding 版本、数据血缘、访问策略、Rerank、答案评测和安全治理。</p><p>因此产品选择不是“有没有向量数据库”这么简单，而是要看平台处在什么阶段：</p><table tabindex="0"><thead><tr><th>阶段</th><th>更常见选择</th><th>关键判断</th></tr></thead><tbody><tr><td>原型验证</td><td>Chroma、FAISS、pgvector</td><td>先验证切分、Embedding、召回和问答链路</td></tr><tr><td>中小规模业务系统</td><td>pgvector、Elasticsearch / OpenSearch Vector、轻量向量库</td><td>看是否需要和关系数据、权限、全文检索放在同一个系统里</td></tr><tr><td>大规模语义检索</td><td>Milvus、Qdrant、Weaviate、Pinecone</td><td>看并发、索引构建、过滤、混合检索、运维和多租户要求</td></tr><tr><td>企业级 AI 数据平台</td><td>向量库 + 元数据治理 + 权限服务 + 评测系统</td><td>向量库只负责召回层，可信边界由平台共同完成</td></tr></tbody></table><h3 id="_10-6-postgresql-与向量数据库" tabindex="-1">10.6 PostgreSQL 与向量数据库 <a class="header-anchor" href="#_10-6-postgresql-与向量数据库" aria-label="Permalink to &quot;10.6 PostgreSQL 与向量数据库&quot;">​</a></h3><p>PostgreSQL 通过 pgvector 可以保存向量并进行相似性检索。</p><p>它适合：</p><ul><li>中小规模 RAG。</li><li>元数据与向量共存。</li><li>权限过滤和向量检索结合。</li><li>早期产品原型。</li><li>企业内部知识库起步阶段。</li></ul><p>例如一张 <code>chunks</code> 表：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>chunks</span></span>
<span class="line"><span>├── chunk_id</span></span>
<span class="line"><span>├── document_id</span></span>
<span class="line"><span>├── collection_id</span></span>
<span class="line"><span>├── content</span></span>
<span class="line"><span>├── embedding</span></span>
<span class="line"><span>├── metadata</span></span>
<span class="line"><span>├── acl_scope</span></span>
<span class="line"><span>├── chunk_version</span></span>
<span class="line"><span>└── embedding_version</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><p>PostgreSQL 的优势是结构化控制强：权限、元数据、事务、版本和业务字段可以放在一起。</p><p>但当向量规模、并发、索引更新、分布式检索和多租户隔离要求上升时，专门向量数据库更合适。</p><p>核心判断是：</p><blockquote><p>pgvector 是 PostgreSQL 通向 AI 数据系统的桥梁，但不是所有向量检索规模的终点。</p></blockquote><h3 id="_10-7-rag-数据链路" tabindex="-1">10.7 RAG 数据链路 <a class="header-anchor" href="#_10-7-rag-数据链路" aria-label="Permalink to &quot;10.7 RAG 数据链路&quot;">​</a></h3><p>完整 RAG 链路是：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>文档采集</span></span>
<span class="line"><span>  -&gt; 文档解析</span></span>
<span class="line"><span>  -&gt; Chunking</span></span>
<span class="line"><span>  -&gt; Embedding</span></span>
<span class="line"><span>  -&gt; 向量入库</span></span>
<span class="line"><span>  -&gt; Query Embedding</span></span>
<span class="line"><span>  -&gt; Vector Search</span></span>
<span class="line"><span>  -&gt; Metadata Filter</span></span>
<span class="line"><span>  -&gt; Rerank</span></span>
<span class="line"><span>  -&gt; Context Assembly</span></span>
<span class="line"><span>  -&gt; LLM Generation</span></span>
<span class="line"><span>  -&gt; Evaluation</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><p>每一步都会影响答案质量。</p><p>文档解析错误，后面检索再快也没用。</p><p>Chunk 切分不合理，召回上下文会碎。</p><p>Embedding 模型不适合领域，语义相似性会偏。</p><p>没有权限过滤，可能泄露数据。</p><p>没有评测，系统无法判断改动是否变好。</p><h3 id="_10-8-混合检索" tabindex="-1">10.8 混合检索 <a class="header-anchor" href="#_10-8-混合检索" aria-label="Permalink to &quot;10.8 混合检索&quot;">​</a></h3><p>向量检索擅长语义相似，但不擅长所有问题。</p><p>关键词检索擅长精确词匹配。</p><p>全文检索和 BM25 擅长词项相关性。</p><p>元数据过滤控制范围。</p><p>Reranking 对候选结果重新排序。</p><p>混合检索的目标是结合这些能力：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Metadata Filter</span></span>
<span class="line"><span>  -&gt; BM25 / Keyword Search</span></span>
<span class="line"><span>  -&gt; Vector Search</span></span>
<span class="line"><span>  -&gt; Score Fusion</span></span>
<span class="line"><span>  -&gt; Rerank</span></span>
<span class="line"><span>  -&gt; Context Assembly</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>核心判断是：</p><blockquote><p>高质量 RAG 很少只靠单一路径召回，通常需要关键词、向量、元数据和重排协同。</p></blockquote><h3 id="_10-9-向量数据库在大数据体系中的位置" tabindex="-1">10.9 向量数据库在大数据体系中的位置 <a class="header-anchor" href="#_10-9-向量数据库在大数据体系中的位置" aria-label="Permalink to &quot;10.9 向量数据库在大数据体系中的位置&quot;">​</a></h3><p>向量数据库不是孤岛。</p><p>它通常和这些系统协同：</p><ul><li>PostgreSQL 保存元数据、权限、任务状态。</li><li>对象存储保存原始文件。</li><li>Spark 处理大规模离线 Embedding。</li><li>Kafka / Flink 处理实时向量更新。</li><li>数据湖保存文档和中间产物。</li><li>LLM / Agent 使用检索结果生成答案。</li><li>数据治理系统记录版本、血缘、权限和评测。</li></ul><h3 id="深度展开-向量数据库如何落到真实系统" tabindex="-1">深度展开：向量数据库如何落到真实系统 <a class="header-anchor" href="#深度展开-向量数据库如何落到真实系统" aria-label="Permalink to &quot;深度展开：向量数据库如何落到真实系统&quot;">​</a></h3><p>本节补齐本章的工程细节。阅读时不要只记住概念名称，而要把它放回“输入是什么、处理路径是什么、输出给谁、边界在哪里、如何验证”的链路中。</p><h4 id="一、它从什么问题开始" tabindex="-1">一、它从什么问题开始 <a class="header-anchor" href="#一、它从什么问题开始" aria-label="Permalink to &quot;一、它从什么问题开始&quot;">​</a></h4><p>结构化 SQL 擅长精确匹配和聚合，但文档、图片、代码和问答需要语义相似度检索。</p><p>这个问题通常不会以技术名词出现，而是以业务现象出现：报表变慢、指标不一致、实时看板延迟、RAG 召回不稳定、数据无法追溯、项目 Demo 无法验收。能不能把现象还原成系统问题，是本书要训练的第一层能力。</p><h4 id="二、输入数据和前置判断" tabindex="-1">二、输入数据和前置判断 <a class="header-anchor" href="#二、输入数据和前置判断" aria-label="Permalink to &quot;二、输入数据和前置判断&quot;">​</a></h4><p>输入是原始文档、切分后的 Chunk、Embedding 模型版本、向量、元数据、权限字段和用户查询。</p><p>在动手之前，至少要确认四件事：</p><table tabindex="0"><thead><tr><th>判断项</th><th>要回答的问题</th></tr></thead><tbody><tr><td>数据粒度</td><td>一行代表什么事实，是用户、订单、订单明细、事件、文件、Chunk，还是一条关系？</td></tr><tr><td>时间边界</td><td>使用创建时间、更新时间、支付时间、事件时间，还是处理时间？</td></tr><tr><td>状态边界</td><td>哪些状态算有效，哪些测试、取消、退款、重复或迟到数据要排除？</td></tr><tr><td>责任边界</td><td>这个环节负责记录事实、生产指标、加速查询、治理质量，还是服务 AI 应用？</td></tr></tbody></table><h4 id="三、处理路径" tabindex="-1">三、处理路径 <a class="header-anchor" href="#三、处理路径" aria-label="Permalink to &quot;三、处理路径&quot;">​</a></h4><p>处理路径是解析文档、切分 Chunk、生成 Embedding、写入向量索引，查询时生成 Query Embedding，做向量召回、过滤、重排和上下文拼装。</p><p>这条路径应该能被写成可执行流程，而不是停留在术语解释。一个合格的设计至少要说明：数据从哪里来、经过哪些转换、写到哪里、谁消费、失败后如何重跑、结果如何校验。</p><h4 id="四、在真实平台中的位置" tabindex="-1">四、在真实平台中的位置 <a class="header-anchor" href="#四、在真实平台中的位置" aria-label="Permalink to &quot;四、在真实平台中的位置&quot;">​</a></h4><p>真实平台中 pgvector 适合和 PostgreSQL 元数据一起做中小规模检索，Milvus、Qdrant 等专门系统适合更大规模和更复杂索引策略，RAG 服务负责把召回结果交给模型。</p><p>平台位置决定了它和前后系统的关系。不要孤立地问“这个技术好不好”，而要问：</p><ul><li>它继承了上一层什么问题？</li><li>它把什么复杂度转移给了下一层？</li><li>它的输出是否能被复用、追溯和治理？</li><li>它是否改变了数据粒度、延迟、一致性或权限边界？</li></ul><h4 id="五、边界和失败模式" tabindex="-1">五、边界和失败模式 <a class="header-anchor" href="#五、边界和失败模式" aria-label="Permalink to &quot;五、边界和失败模式&quot;">​</a></h4><p>向量检索解决语义相似，不解决事实正确性、权限隔离、结构化统计、数据血缘和答案评测。RAG 质量还取决于解析、切分、元数据和重排。</p><p>常见失败信号可以这样检查：</p><table tabindex="0"><thead><tr><th>失败信号</th><th>应该追问什么</th></tr></thead><tbody><tr><td>关键词搜不到同义表达</td><td>定位到具体输入、口径、链路、边界或治理责任。</td></tr><tr><td>召回结果语义相关但权限不正确</td><td>定位到具体输入、口径、链路、边界或治理责任。</td></tr><tr><td>Chunk 太大导致上下文噪声</td><td>定位到具体输入、口径、链路、边界或治理责任。</td></tr><tr><td>Embedding 模型升级后结果漂移</td><td>定位到具体输入、口径、链路、边界或治理责任。</td></tr></tbody></table><h4 id="六、可操作练习" tabindex="-1">六、可操作练习 <a class="header-anchor" href="#六、可操作练习" aria-label="Permalink to &quot;六、可操作练习&quot;">​</a></h4><p>为一组产品文档设计 RAG 数据表：document、chunk、embedding、metadata、permission、retrieval_log，并写出召回和评测流程。</p><p>练习完成后不要只看“有没有跑通”，还要补一份复盘：</p><ul><li>输入数据是否足以支撑问题？</li><li>口径和边界是否写清楚？</li><li>结果能否被重复计算和对账？</li><li>如果数据量扩大 10 倍，瓶颈会出现在哪里？</li><li>如果接入下游 BI、RAG 或治理系统，还缺哪些元数据？</li></ul><h2 id="系统位置" tabindex="-1">系统位置 <a class="header-anchor" href="#系统位置" aria-label="Permalink to &quot;系统位置&quot;">​</a></h2><p>向量数据库是 AI 数据基础设施中的语义检索层。</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>原始文档 / 网页 / 代码 / 对话 / 图片</span></span>
<span class="line"><span>  -&gt; 采集与解析</span></span>
<span class="line"><span>  -&gt; Chunking</span></span>
<span class="line"><span>  -&gt; Embedding</span></span>
<span class="line"><span>  -&gt; Vector DB / pgvector</span></span>
<span class="line"><span>  -&gt; Hybrid Search / Rerank</span></span>
<span class="line"><span>  -&gt; Context Assembly</span></span>
<span class="line"><span>  -&gt; LLM / Agent</span></span>
<span class="line"><span>  -&gt; Retrieval Logs / Evaluation / Governance</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>它继承前面章节的数据平台能力：对象存储保存原文，PostgreSQL 保存元数据和权限，批处理负责大规模离线 Embedding，实时链路负责增量更新，治理系统负责版本、血缘、质量和访问控制。</p><p>它也引出第 11 章图数据库：向量检索擅长找“语义相似”的内容，但不擅长表达实体之间的显式关系、路径、多跳推理和关系约束。知识图谱和图数据库会补足这部分能力。</p><h2 id="场景案例" tabindex="-1">场景案例 <a class="header-anchor" href="#场景案例" aria-label="Permalink to &quot;场景案例&quot;">​</a></h2><p>设计一个企业制度 RAG 知识库时，可以把数据模型拆成几类表和存储：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>object_storage</span></span>
<span class="line"><span>  原始 PDF / DOCX / HTML 文件</span></span>
<span class="line"><span></span></span>
<span class="line"><span>documents</span></span>
<span class="line"><span>  一行一个文档，记录来源、标题、部门、版本、权限、解析状态</span></span>
<span class="line"><span></span></span>
<span class="line"><span>chunks</span></span>
<span class="line"><span>  一行一个文本块，记录 document_id、章节位置、chunk 文本、chunk_version</span></span>
<span class="line"><span></span></span>
<span class="line"><span>embeddings</span></span>
<span class="line"><span>  一行一个向量，记录 chunk_id、embedding_model、embedding_version、vector</span></span>
<span class="line"><span></span></span>
<span class="line"><span>retrieval_logs</span></span>
<span class="line"><span>  一行一次检索，记录 query、过滤条件、召回结果、点击、反馈</span></span>
<span class="line"><span></span></span>
<span class="line"><span>evaluations</span></span>
<span class="line"><span>  一行一个评测样本，记录问题、标准答案、期望来源、实际召回和评分</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br></div></div><p>用户提问“出差打车超过预算还能报销吗？”时，链路不应只做向量 Top-K：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Query</span></span>
<span class="line"><span>  -&gt; 判断用户权限和所在部门</span></span>
<span class="line"><span>  -&gt; 关键词 + 向量混合召回</span></span>
<span class="line"><span>  -&gt; 过滤过期制度和不可见文档</span></span>
<span class="line"><span>  -&gt; Rerank</span></span>
<span class="line"><span>  -&gt; 组装带来源和章节位置的上下文</span></span>
<span class="line"><span>  -&gt; LLM 生成答案</span></span>
<span class="line"><span>  -&gt; 记录检索日志和用户反馈</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>这个案例说明：向量数据库是关键组件，但答案质量来自整条 RAG 数据链路，而不是单次相似度检索。</p><h2 id="常见误区" tabindex="-1">常见误区 <a class="header-anchor" href="#常见误区" aria-label="Permalink to &quot;常见误区&quot;">​</a></h2><p><strong>误区一：向量数据库可以替代关系型数据库。</strong></p><p>向量库解决相似性检索，不解决强事务、复杂关系建模、指标分析和完整数据治理。</p><p><strong>误区二：Embedding 后就能问答。</strong></p><p>RAG 还需要解析、切分、检索、过滤、重排、上下文组装、生成和评测。</p><p><strong>误区三：召回分数高就一定答案正确。</strong></p><p>相似不等于事实正确，也不等于权限可见或上下文完整。</p><p><strong>误区四：只要换更强的 Embedding 模型，RAG 就一定变好。</strong></p><p>模型很重要，但文档解析、Chunk 策略、元数据、权限、混合检索、重排和评测同样会决定结果。模型变化还可能要求全量重算向量。</p><p><strong>误区五：向量库里只需要保存向量。</strong></p><p>真实系统必须保存来源、版本、权限、租户、文档结构、时间、解析状态和检索日志。没有这些元数据，检索结果无法治理、无法追溯、无法安全使用。</p><h2 id="实战任务" tabindex="-1">实战任务 <a class="header-anchor" href="#实战任务" aria-label="Permalink to &quot;实战任务&quot;">​</a></h2><p>设计一个 RAG 知识库数据模型：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>documents</span></span>
<span class="line"><span>chunks</span></span>
<span class="line"><span>embeddings</span></span>
<span class="line"><span>collections</span></span>
<span class="line"><span>retrieval_logs</span></span>
<span class="line"><span>evaluations</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>要求说明：</p><ul><li>每张表一行代表什么。</li><li>原始文档保存在哪里。</li><li>Chunk 如何关联文档。</li><li>Embedding 如何记录模型版本。</li><li>检索日志如何用于评测。</li><li>权限过滤如何进入检索。</li></ul><p>补充要求：</p><ul><li>设计 <code>documents</code>、<code>chunks</code>、<code>embeddings</code> 的主键和外键关系。</li><li>为 <code>embedding_model</code>、<code>embedding_version</code>、<code>chunk_version</code> 设计升级策略。</li><li>说明如何处理文档删除、文档更新和权限变化。</li><li>设计一次 RAG 评测：至少包含 10 个问题、标准来源、期望召回 chunk、答案评分规则。</li><li>对比 pgvector 和专门向量数据库在这个场景中的边界。</li></ul><h2 id="小结引出下一章" tabindex="-1">小结引出下一章 <a class="header-anchor" href="#小结引出下一章" aria-label="Permalink to &quot;小结引出下一章&quot;">​</a></h2><p>向量数据库让语义相似性成为可查询对象。</p><p>它把非结构化数据接入 AI 应用，但它必须和元数据、权限、对象存储、评测、数据链路和治理协同。</p><p>下一章进入图数据库。</p><p>因为除了语义相似，AI 和数据分析还经常需要理解实体之间的关系网络。</p>`,161))])}const v=e(r,[["render",d]]);export{g as __pageData,v as default};
